timeSeriesQuery.prometheusQuery:
(

  sum(
    count_over_time(
      (
        count_over_time(
          {
            __name__="kubernetes.io/anthos/node/cpu/allocatable_cores",
            cluster_name=~"${cluster_name.value}",
            project_id=~"${project_id.value}"
          }[5m] # have we seen anything in the last 5 mins as a heartbeat
        ) 
      )[${__interval}:5m]  # how many ups have we seen in 5 min chunks over the interval
    )
  )
  or vector(0)
)
/
(
  ### DENOMINATOR: (Total Inventory) * (Max possible 5m intervals)
  (
    sum(
      count by (node_name) (
        last_over_time(
          {
            __name__="kubernetes.io/anthos/node/cpu/allocatable_cores",
            cluster_name=~"${cluster_name.value}",
            project_id=~"${project_id.value}"
          }[10d] # we decided to place this hardcoded as a value of how many days should we consider that a cluster is part of the inventory
        )
      )
    )
  )
  * ### Calculates how many 5m steps exist in the current dashboard interval
  ### e.g., if interval is 1h, this returns 12.
  count_over_time(vector(1)[${__interval}:5m])
)
* 100

count by (version) (
  max by (cluster_name, version) (
    avg_over_time(
      {
        __name__="edgecontainer.googleapis.com/edge_cluster/current_cluster_version",
        monitored_resource="edgecontainer.googleapis.com/EdgeCluster",
        cluster_name=~"${cluster_name.value}"
      }[24h]
    )
  )
)

(
  # ---------------------------------------------------------------------
  # PART A: Clusters in explicit failure states
  # Result Status: RECONCILING, PROVISIONING, or ERROR
  # ---------------------------------------------------------------------
  max by (status, cluster_name) (
    last_over_time({
      __name__="edgecontainer.googleapis.com/edge_cluster/lifecycle_status",
      monitored_resource="edgecontainer.googleapis.com/EdgeCluster",
      status=~"RECONCILING|PROVISIONING|ERROR",
      cluster_name=~"${cluster_name.value}"
    }[24h])
  )
)
OR on (cluster_name) (
  # ---------------------------------------------------------------------
  # PART B: Clusters that are RUNNING but have Version Drift
  # Result Status: Overwritten to "UPGRADE_PAUSED"
  # ---------------------------------------------------------------------
  label_replace(
    (
      # 1. Calculate Drift (Node != Cluster)
      (
        max by (cluster_name, current_node_version) (
          last_over_time({
            __name__="edgecontainer.googleapis.com/node/current_node_version",
            monitored_resource="edgecontainer.googleapis.com/Node"
          }[24h])
        )
        unless on (cluster_name, current_node_version)
        label_replace(
          max by (cluster_name, version) (
            last_over_time({
              __name__="edgecontainer.googleapis.com/edge_cluster/current_cluster_version",
              monitored_resource="edgecontainer.googleapis.com/EdgeCluster"
            }[24h])
          ),
          "current_node_version", "$1", "version", "(.*)"
        )
      )
      # 2. Guard: Ensure it's technically RUNNING, and pull that label in
      * on (cluster_name) group_left(status)
      max by (cluster_name, status) (
        last_over_time({
          __name__="edgecontainer.googleapis.com/edge_cluster/lifecycle_status",
          monitored_resource="edgecontainer.googleapis.com/EdgeCluster",
          status="RUNNING",
          cluster_name=~"${cluster_name.value}"
        }[24h])
      )
    ),
    # 3. Rename "RUNNING" to "UPGRADE_PAUSED" for readability
    "status", "UPGRADE_PAUSED", "status", ".*"
  )
)

(
  max_over_time(kubernetes_io:anthos_node_cpu_core_usage_time{monitored_resource="k8s_node", project_id=~"${project_id.value}"}[10d]) 
  unless 
  kubernetes_io:anthos_node_cpu_core_usage_time{monitored_resource="k8s_node", project_id=~"${project_id.value}"}
)
and on(cluster_name)
(
  count by (cluster_name) (
    kubernetes_io:anthos_node_cpu_core_usage_time{monitored_resource="k8s_node", project_id=~"${project_id.value}"}
  ) < 3
)
